using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"  Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// 2a – type IS resolvable (default reflection resolver handles Person)
if (options.TryGetTypeInfo<Person>(out var resolvedInfo))
    Console.WriteLine($"TryGetTypeInfo<Person> → resolved ({resolvedInfo!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person> → not available");

// 2b – type is NOT resolvable (empty resolver knows nothing)
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
        .WithAddedModifier(ti =>
        {
            // Strip every type so nothing resolves
            if (ti.Type == typeof(Order))
                throw new NotSupportedException();
        })
};

// Use a resolver chain that explicitly has NO resolver for Order
var limited = new JsonSerializerOptions { TypeInfoResolver = null };

if (limited.TryGetTypeInfo<Order>(out var orderInfo))
    Console.WriteLine($"TryGetTypeInfo<Order> → resolved ({orderInfo!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Order> → not available (no resolver configured)");

// --- records used above ---
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

